33	// Lookup the canonical key in a case-insensitive way
34	function lookupDescriptionKey(descriptions, target) {
35	  if (descriptions[target]) return target;
36	  const lower = target.toLowerCase();
37	  for (const key of Object.keys(descriptions)) {
38	    if (key.toLowerCase() === lower) return key;
39	  }
40	  return null;
41	}
