64	// Check if Terminal has an open tab running "claude -r <teamName>"
65	function checkClaudeTerminalProcess(teamName) {
66	  try {
67	    // Escape dangerous shell characters from teamName
68	    const escapedName = teamName.replace(/['"\\$`;]/g, '');
69	    const output = execSync(
70	      `ps aux 2>/dev/null | grep -F "claude -r ${escapedName}" | grep -v grep`,
71	      { stdio: ['pipe', 'pipe', 'pipe'], encoding: 'utf8', timeout: 3000 }
72	    );
73	    return output && output.trim().length > 0;
74	  } catch (e) {
75	    return false;
76	  }
77	}
