150	// Get all team info
151	function getTeams() {
152	  const teams = [];
153	  if (!fs.existsSync(TEAMS_DIR)) return teams;
154	
155	  const teamDirs = fs.readdirSync(TEAMS_DIR);
156	
157	  for (const teamName of teamDirs) {
158	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
159	    try {
160	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
161	      const taskListPath = path.join(CLAUDE_DIR, 'tasks', teamName);
162	
163	      let taskStatus = { total: 0, completed: 0, inProgress: 0, pending: 0 };
164	      if (fs.existsSync(taskListPath)) {
165	        const taskFiles = fs.readdirSync(taskListPath).filter(f => f.endsWith('.json'));
166	        for (const taskFile of taskFiles) {
167	          try {
168	            const task = JSON.parse(fs.readFileSync(path.join(taskListPath, taskFile), 'utf8'));
169	            taskStatus.total++;
170	            if (task.status === 'completed') taskStatus.completed++;
171	            else if (task.status === 'in_progress') taskStatus.inProgress++;
172	            else if (task.status === 'pending') taskStatus.pending++;
173	          } catch {}
174	        }
175	      }
176	
177	      teams.push({
178	        name: teamName,
179	        description: config.description || '',
180	        memberCount: config.members?.length || 0,
181	        taskStatus
182	      });
183	    } catch {}
184	  }
185	
186	  return teams;
187	}
