189	// Build environment from user settings
190	function buildEnvScript() {
191	  let settingsEnv = {};
192	  try {
193	    const settingsPath = path.join(process.env.HOME, '.claude', 'settings.json');
194	    const settings = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
195	    settingsEnv = settings.env || {};
