236	// Parse CLI args string into array (handles --flag and "quoted strings")
237	function parseCliArgs(input) {
238	  const args = [];
239	  let current = '';
240	  let inQuote = false;
241	
242	  for (let i = 0; i < input.length; i++) {
243	    const c = input[i];
244	    if (c === '"' && !inQuote) {
245	      inQuote = true;
246	    } else if (c === '"' && inQuote) {
247	      inQuote = false;
248	      args.push(current);
249	      current = '';
250	    } else if (c === ' ' && !inQuote) {
251	      if (current) args.push(current);
252	      current = '';
253	    } else {
254	      current += c;
255	    }
256	  }
257	  if (current) args.push(current);
258	  return args;
259	}
