397	// Since OpenRouter doesn't support Claude CLI context management,
398	// this creates a registered agent entry that users can manage from the dashboard.
399	// Status shows as "registered" — users can resume the session manually.
400	app.post('/api/spawn', (req, res) => {
401	  try {
402	    const { name, role, prompt, description } = req.body;
403	    const fullPrompt = prompt || `${name} is a ${role} agent.`;
404	
405	    const safeName = name.toLowerCase().replace(/[^a-z0-9]/g, '-');
