417	        cmd = `--agent=trevor "${fullPrompt.replace(/"/g, '\\"')}"`;
418	      } else {
419	        cmd = `"${fullPrompt.replace(/"/g, '\\"')}"`;
420	      }
421	
422	      const result = spawnBackgroundProcess(backgroundId, cmd);
423	      pid = result.pid;
424	      logFile = result.logFile;
425	    }
426	
427	    if (pid) savePid(`${teamName}.pid`, pid);
428	
429	    // Save description
430	    if (description) {
431	      const descriptions = loadDescriptions();
432	      descriptions[name] = description;
433	      saveDescriptions(descriptions);
434	    }
435	
436	    // Create team entry so the dashboard can discover this agent
437	    const teamDir = path.join(TEAMS_DIR, teamName);
438	    const taskListDir = path.join(CLAUDE_DIR, 'tasks', teamName);
439	
440	    fs.mkdirSync(teamDir, { recursive: true });
441	    fs.mkdirSync(taskListDir, { recursive: true });
442	
443	    const teamConfig = {
444	      description: description || `${name} — ${role} agent`,
445	      leaderSessionId: null,
446	      createdAt: Date.now(),
447	      backgroundId,
448	      members: [{
449	        agentId: `agent-${safeName}`,
450	        name,
451	        agentType: role || 'general-purpose',
452	        backgroundId
453	      }]
454	    };
455	    fs.writeFileSync(
456	      path.join(teamDir, 'config.json'),
457	      JSON.stringify(teamConfig, null, 2)
458	    );
459	
460	    res.json({
461	      success: true,
462	      message: canSpawn
463	        ? `Agent "${name}" spawned in background`
464	        : `Agent "${name}" registered (OpenRouter — resume manually)`,
465	      name,
466	      teamName,
467	      logFile,
468	      canSpawn,
469	      resumeCommand: canSpawn ? null : `claude -r ${teamName}`
470	    });
471	  } catch (err) {
