511	// Open a new Terminal.app tab and run a command via osascript
512	// Writes command to .sh + AppleScript to temp files to avoid all quoting issues
513	function openTerminalTab(title, command) {
514	  const tmpDir = path.join(__dirname, '.tmp');
515	  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
516	
517	  // SAME timestamp for both files so AppleScript can find the shell script
518	  const ts = Date.now();
519	
520	  // Write the actual command to a shell script
521	  const shellFile = path.join(tmpDir, `launch-${ts}.sh`);
522	  fs.writeFileSync(shellFile, `#!/bin/bash\necho "=== Agent: ${title} ==="\n${command}\n`, 'utf8');
523	  fs.chmodSync(shellFile, '755');
524	
525	  // Escape the path for AppleScript (no quotes needed if no spaces in tmp path)
526	  const safeShellPath = shellFile.replace(/"/g, '\\"').replace(/\\/g, '\\\\');
527	  const safeTitle = title.replace(/"/g, '\\"');
528	
529	  const appleScript = `tell application "Terminal"
530	    set winId to do script "${safeShellPath}"
531	    set custom title of winId to "${safeTitle}"
532	    set title displays custom title of winId to true
533	    set miniaturized of winId to true
534	end tell
535	`;
536	  const scriptFile = path.join(tmpDir, `launch-${ts}.scpt`);
537	  fs.writeFileSync(scriptFile, appleScript, 'utf8');
538	
539	  try {
540	    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 10000 });
541	    // Clean up after a delay (Terminal has already sourced the files)
542	    setTimeout(() => {
543	      try { fs.unlinkSync(shellFile); } catch {}
544	      try { fs.unlinkSync(scriptFile); } catch {}
545	    }, 10000);
546	    return true;
547	  } catch (e) {
548	    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
549	    try { fs.unlinkSync(shellFile); } catch {}
550	    try { fs.unlinkSync(scriptFile); } catch {}
551	    return false;
552	  }
553	}
