    ANTHROPIC_BASE_URL: settingsEnv.ANTHROPIC_BASE_URL || '',
    ANTHROPIC_AUTH_TOKEN: settingsEnv.ANTHROPIC_AUTH_TOKEN || '',
    ANTHROPIC_API_KEY: settingsEnv.ANTHROPIC_API_KEY || '',
