// Open a new Terminal.app tab and run a command via inline osascript
// No intermediate files — command is passed directly in the AppleScript string
// Base64 encodes the script to avoid all shell quoting issues; deletes before execution
function openTerminalTab(title, command) {
  const safeTitle = title
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"');

  // Escape the command for AppleScript string literals
  // Must handle: backslashes (first), double-quotes, dollar signs (AppleScript variable prefix)
  const safeCommand = command
    .replace(/\\/g, '\\\\')
    .replace(/"/g, '\\"')
    .replace(/\$/g, '\\$');

  const appleScript = [
    `tell application "Terminal"`,
    `    do script "${safeCommand}"`,
    `    tell window 1 to set custom title to "${safeTitle}"`,
    `    tell window 1 to set title displays custom title to true`,
    `    tell window 1 to set miniaturized to true`,
    `end tell`
  ].join('\n');

  // Base64 encode to bypass all shell quoting issues
  const b64 = Buffer.from(appleScript, 'utf8').toString('base64');

  try {
    execSync(`printf '%s' ${b64} | base64 --decode | osascript -`, { stdio: 'pipe', timeout: 10000 });
    return true;
  } catch (e) {
    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
    return false;
  }
}

